using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Runtime.InteropServices;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip no longer defaults to system rendering.
        // Explicitly set RenderMode to preserve the .NET 8 look.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }
}

public class MyPropertyEditor : UITypeEditor
{
    public override object EditValue(ITypeDescriptorContext context,
        IServiceProvider provider, object value)
    {
        var svc = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (svc == null)
            return value;

        var control = BuildEditControl(value);

        // .NET 9: DropDownControl now throws ArgumentNullException when passed null.
        // Always guard against a null control before calling.
        if (control != null)
        {
            svc.DropDownControl(control);
            value = control.Tag;
        }

        return value;
    }

    private Control BuildEditControl(object value)
    {
        if (value == null)
            return null;

        var list = new ListBox();
        list.Items.Add(value);
        list.Tag = value;
        return list;
    }
}

